#!/usr/bin/env bash
# GENERATED by `ggen sync` from .specify/templates/verify/produce_evidence_check_sh.sh.tera
# (ggen.toml's own declarative-rules mirror of packs/ggen-verify-pack's
# templates/produce_evidence_check_sh.tmpl -- see that file's header for the
# schema note on why this repo needs its own copy). Evidence-class producer:
# checks the ver:RequiredCheck set's COMPLETENESS (every required name
# present as a ver:Check in evidence/ontology.ttl) and FRESHNESS (age of the
# evidence commit vs HEAD within the ontology-declared window; falls back to
# file mtime vs now when the file is untracked). Emits ver:EvidenceCheck with
# the REAL result + the required-set digest (the evidence class identity).
# Always exits 0 itself; judgment happens at sync.
set -uo pipefail
cd "$(dirname "$0")/.."
mkdir -p evidence/producers
REQUIRED_NAMES=('build' 'byte-identity' 'clippy-reference-gate' 'test-workspace' )
WINDOW_HOURS=168

CODE=0
REASON="ok"

# Completeness: every required name must appear as a recorded ver:Check.
if [ ! -f evidence/ontology.ttl ]; then
  CODE=1
  REASON="evidence/ontology.ttl missing"
else
  for name in "${REQUIRED_NAMES[@]}"; do
    if ! grep -q "ver:name \"$name\"" evidence/ontology.ttl; then
      CODE=1
      REASON="required check '$name' missing from evidence"
      break
    fi
  done
fi

# Freshness: evidence commit age vs HEAD commit time, within the window.
if [ "$CODE" -eq 0 ]; then
  EV_TS="$(git log -1 --format=%ct -- evidence/ontology.ttl 2>/dev/null || true)"
  if [ -n "$EV_TS" ]; then
    HEAD_TS="$(git log -1 --format=%ct HEAD 2>/dev/null || echo "$EV_TS")"
  else
    # Untracked evidence: fall back to mtime vs wall clock.
    EV_TS="$(stat -f %m evidence/ontology.ttl 2>/dev/null || stat -c %Y evidence/ontology.ttl)"
    HEAD_TS="$(date +%s)"
  fi
  AGE=$((HEAD_TS - EV_TS))
  if [ "$AGE" -gt $((WINDOW_HOURS * 3600)) ]; then
    CODE=1
    REASON="evidence stale: ${AGE}s old vs ${WINDOW_HOURS}h window"
  fi
fi

sha256_text() {
  if command -v sha256sum >/dev/null 2>&1; then printf '%s' "$1" | sha256sum | cut -d' ' -f1
  else printf '%s' "$1" | shasum -a 256 | cut -d' ' -f1; fi
}
REQUIRED_SET_DIGEST="$(sha256_text "$(printf '%s\n' "${REQUIRED_NAMES[@]}" | LC_ALL=C sort)")"

OUT=evidence/producers/evidence-check.ttl
{
  echo "# GENERATED by scripts/produce-evidence-check.sh -- do not edit."
  echo "@prefix ver: <http://seanchatmangpt.github.io/packs/ggen-verify#> ."
  echo
  echo "ver:evidence-check a ver:EvidenceCheck ;"
  echo "    ver:exitCode $CODE ;"
  echo "    ver:requiredSetDigest \"$REQUIRED_SET_DIGEST\" ;"
  echo "    ver:summary \"$REASON\" ."
} > "$OUT"
echo "produce-evidence-check.sh: exit $CODE ($REASON) -> $OUT"
exit 0
